  // === GIFT-PACKAGING ===
  'luxury-magnetic-gift-box': { name: 'Luxus Magnetische Geschenkbox', closure: 'Magnetisch', tagline: 'Versteckter magnetischer Verschluss für Premium-Retail-Verpackung', intro: 'Eine Premium-Geschenkbox mit verdeckten Neodym-Magneten im Deckel. Das sauberste mögliche Äußere mit befriedigendem Snap-Close-Gefühl — ideal für Kosmetik, Uhren und High-End-Retail-Verpackung, wo das Unboxing-Erlebnis zählt.' },
