  'drawer-wooden-gift-box': { name: 'Geschenkbox aus Holz mit Schublade', closure: 'Schublade', tagline: 'Auszieh-Schublade für High-End-Präsentationen', intro: 'Eine Geschenkbox im Schubladen-Stil, die sich sanft auszieht und den Inhalt offenbart. Kombiniert das substantielle Gefühl einer Scharnierbox mit der Überraschung einer Präsentationsschublade. Einzelne oder mehrstöckige Konfigurationen verfügbar.' },
  'liftoff-lid-gift-box': { name: 'Geschenkbox mit Abnehmbarem Deckel', closure: 'Abnehmbar', tagline: 'Einfache Zwei-Teile-Konstruktion, klassisch und sauber', intro: 'Eine traditionelle Box mit abnehmbarem Deckel — eine separate Oberseite, die sauber abhebt. Das einfachste, sauberste Geschenkbox-Format, mit einem großzügigen flachen Deckel für Branding. Ideal für Kosmetik, Bastelsets und jede Anwendung, die eine „Enthüllungs"-Öffnung bevorzugt.' },

  // === WATCH-JEWELRY ===
  'luxury-velvet-ring-box': { name: 'Luxus Samt-Ringbox', closure: 'Mit Scharnier', tagline: 'Massivholzbox mit Samtfutter für Ringe', intro: 'Eine Premium-Ringbox aus Massivholz mit komplett samtgefüttertem Innenraum. Verdecktes Scharnier und magnetischer Verschluss; der Ringschlitz ist kalibriert, um kleine Stücke fest zu halten, ohne das Metall zu markieren. Die perfekte Antrags- oder Präsentationsbox.' },
